INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (11, 10, 1, 0, 1, 130911, 66032, 0, "アオイさんですよね～っ！？\nグランドリームパークへようこそっ♪\n本日はおひとりさまですますか？", 0, 5146066);
INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (91, "", "", "", "", 0, 66033, "", "", "", 5146066);
