INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (11, 15, 1, 0, 1, 104011, 66037, 0, "ぶひゃおおおお！？\nすすす、すみません！\nぼっちは強制退園ですよね！\n今すぐ出ていきますので～！", 0, 5146066);
INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (91, "", "", "", "", 0, 66038, "", "", "", 5146066);
