INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (11, 10, 1, 0, 1, 130911, 66042, 0, "待ってください待ってくださいっ！\n強制退園ってなんですます～っ！？\nそんなことしませんですですっ！", 0, 5146066);
